{"content":"
export interface User {
  id: string;
  email: string;
  name: string;
  credits: number;
  plan: 'free' | 'pro' | 'enterprise';
  workspaceId?: string;
  role?: 'owner' | 'admin' | 'analyst' | 'viewer';
}

export interface Project {
  id: string;
  name: string;
  domain: string;
  logo?: string;
  status: 'active' | 'paused';
  lastRun?: string; // ISO Date
  visibilityScore: number;
  trend: number; // Percentage variation
  nextRun?: string;
}

export interface Recommendation {
  id: string;
  priority: 'critical' | 'high' | 'medium' | 'low';
  title: string;
  description: string;
  action: string;
  effort: 'low' | 'medium' | 'high';
  impact: 'low' | 'medium' | 'high';
  category: string;
}

export interface CategoryScore {
  name: string;
  score: number;
  weight: number;
  items: Array<{
    status: 'success' | 'warning' | 'error';
    message: string;
    recommendation?: string;
  }>;
}

export interface AnalysisResult {
  url: string;
  timestamp: string;
  globalScore: number;
  categories: Record<string, CategoryScore>; 
  recommendations: Recommendation[];
  aiCitation: {
    before: string;
    after: string;
    probability: number; 
  };
}

export interface HistoryItem {
  id: string;
  url: string;
  score: number;
  date: string;
}

export interface GeneratedSolution {
  title: string;
  explanation: string;
  content: string; // Code or Text
  type: 'code' | 'text';
  language?: 'html' | 'json' | 'text';
  implementationSteps: string[]; 
}
"}

{"content":"import React, { useState, useRef } from 'react';
import { 
  Search, Globe, Brain, Target, BarChart3, CheckCircle2, AlertTriangle, 
  XCircle, Sparkles, ArrowRight, Download, RefreshCw, Lightbulb, 
  Clock, Award, Rocket, Play, Loader2, Quote, Layers, Bot, Activity, Share2 
} from 'lucide-react';

// --- TYPES POUR TYPESCRIPT ---
interface AnalysisItem {
  status: 'success' | 'warning' | 'error';
  message: string;
  recommendation?: string | null;
  impact?: 'high' | 'medium' | 'low';
}

interface CategoryData {
  score: number;
  items: AnalysisItem[];
}

interface Recommendation {
  priority: 'critical' | 'high' | 'medium' | 'low';
  title: string;
  description: string;
  action: string;
  impact: number;
  effort: string;
  category: string;
}

// --- COMPOSANTS DE STYLE ---
const NoiseTexture = () => (
  <svg className="fixed inset-0 w-full h-full pointer-events-none opacity-[0.015] z-50" style={{ mixBlendMode: 'overlay' }}>
    <filter id="noise"><feTurbulence type="fractalNoise" baseFrequency="0.8" numOctaves="4" stitchTiles="stitch"/></filter>
    <rect width="100%" height="100%" filter="url(#noise)"/>
  </svg>
);

const GradientOrbs = () => (
  <div className="fixed inset-0 overflow-hidden pointer-events-none">
    <div className="absolute -top-40 -right-40 w-[600px] h-[600px] rounded-full bg-emerald-500/20 blur-3xl animate-pulse" />
    <div className="absolute top-1/2 -left-40 w-[500px] h-[500px] rounded-full bg-blue-500/15 blur-3xl animate-pulse" />
  </div>
);

// --- COMPOSANT PRINCIPAL ---
export default function App() {
  const [url, setUrl] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [analysisComplete, setAnalysisComplete] = useState(false);
  const [activeTab, setActiveTab] = useState('overview');
  const resultsRef = useRef<HTMLDivElement>(null);

  const runAnalysis = () => {
    if (!url) return;
    setIsAnalyzing(true);
    // Simulation d'analyse
    setTimeout(() => {
      setIsAnalyzing(false);
      setAnalysisComplete(true);
    }, 3000);
  };

  return (
    <div className="min-h-screen bg-[#0a0a0f] text-white selection:bg-emerald-500/30 font-sans">
      <NoiseTexture />
      <GradientOrbs />

      {/* Header */}
      <header className="relative z-40 border-b border-white/5 backdrop-blur-md bg-[#0a0a0f]/50 sticky top-0">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-emerald-500 p-2 rounded-xl">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold">CitedBy<span className="text-emerald-400">.ai</span></h1>
          </div>
          <button className="bg-white/5 border border-white/10 px-5 py-2 rounded-full text-sm">Connexion</button>
        </div>
      </header>

      <main className="relative z-10 pt-20 pb-24 px-6">
        {/* Barre de recherche (L'entrée du SaaS) */}
        {!analysisComplete && (
          <div className="max-w-4xl mx-auto text-center">
            <h2 className="text-6xl font-bold mb-6">Faites-vous <span className="text-emerald-400">citer</span> par les IA</h2>
            <p className="text-xl text-white/50 mb-10">Optimisez votre site pour ChatGPT, Claude et Perplexity.</p>

            <div className="relative max-w-2xl mx-auto group">
              <div className="flex bg-white/5 border border-white/10 rounded-2xl p-2">
                <input 
                  className="flex-1 bg-transparent px-4 py-4 outline-none text-lg" 
                  placeholder="https://votre-site.com" 
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                />
                <button 
                  onClick={runAnalysis}
                  disabled={isAnalyzing}
                  className="bg-emerald-500 hover:bg-emerald-400 text-black px-8 py-4 rounded-xl font-bold transition-all"
                >
                  {isAnalyzing ? <Loader2 className="animate-spin" /> : "Analyser"}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* L'interface Tableau de Bord (Une fois l'analyse faite) */}
        {analysisComplete && (
          <div ref={resultsRef} className="max-w-6xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <div className="flex items-center justify-between mb-8 p-6 bg-white/5 border border-white/10 rounded-2xl">
              <div className="flex items-center gap-4">
                <Globe className="w-6 h-6 text-emerald-400" />
                <div>
                  <p className="text-white/40 text-sm">Analyse de</p>
                  <p className="text-white font-medium">{url}</p>
                </div>
              </div>
              <button onClick={() => setAnalysisComplete(false)} className="text-emerald-400 text-sm flex items-center gap-2">
                <RefreshCw className="w-4 h-4" /> Nouvelle analyse
              </button>
            </div>

            {/* Onglets du SaaS */}
            <div className="flex gap-4 mb-8">
              {['overview', 'recommendations', 'ai-preview'].map(t => (
                <button 
                  key={t} 
                  onClick={() => setActiveTab(t)}
                  className={`px-6 py-2 rounded-full text-sm transition-all ${activeTab === t ? 'bg-emerald-500 text-black font-bold' : 'bg-white/5 text-white/50'}`}
                >
                  {t.toUpperCase()}
                </button>
              ))}
            </div>

            {/* Contenu de l'interface */}
            <div className="bg-white/5 border border-white/10 rounded-3xl p-8 min-h-[400px]">
              {activeTab === 'overview' && (
                <div className="text-center py-20">
                  <div className="inline-block relative">
                    <span className="text-8xl font-bold text-emerald-400">72</span>
                    <span className="text-2xl text-white/40">/100</span>
                  </div>
                  <h3 className="text-2xl font-bold mt-4">Score de Citabilité Global</h3>
                  <p className="text-white/50 mt-2">Votre site a une probabilité modérée d'être cité par les IA génératives.</p>
                </div>
              )}
              {activeTab === 'recommendations' && (
                <div className="grid md:grid-cols-2 gap-4">
                  <div className="p-6 bg-red-500/10 border border-red-500/20 rounded-2xl">
                    <h4 className="font-bold text-red-400 flex items-center gap-2"><AlertTriangle className="w-4 h-4"/> Critique</h4>
                    <p className="mt-2 text-sm text-white/70">Ajoutez des données structurées Schema.org FAQPage.</p>
                  </div>
                  <div className="p-6 bg-amber-500/10 border border-amber-500/20 rounded-2xl">
                    <h4 className="font-bold text-amber-400 flex items-center gap-2"><Lightbulb className="w-4 h-4"/> Amélioration</h4>
                    <p className="mt-2 text-sm text-white/70">Utilisez des listes à puces pour vos définitions clés.</p>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}"}

{"content":"import React, { useState } from 'react';
import { User } from '../types';
import { Zap, CreditCard, Check, Download, Star, ArrowLeft, LayoutList, ShieldCheck, Briefcase, Globe, Server, ArrowRight, Loader2 } from 'lucide-react';

interface PlanProps {
  onBack: () => void;
  onNavigateToProjects: () => void;
  user: User | null;
}

const Plan: React.FC<PlanProps> = ({ onBack, onNavigateToProjects, user }) => {
  const [activeTab, setActiveTab] = useState<'my-plan' | 'pricing'>('my-plan');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubscribePro = async () => {
    if (!user || !user.workspaceId) {
        alert("Erreur: ID de workspace manquant. Veuillez vous reconnecter.");
        return;
    }

    setIsLoading(true);
    try {
        const res = await fetch('/api/stripe/checkout', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                workspaceId: user.workspaceId, 
                plan: 'pro' 
            })
        });

        const data = await res.json();

        if (!res.ok) throw new Error(data.error || 'Erreur lors de la création de la session');

        if (data.url) {
            window.location.href = data.url;
        }
    } catch (error) {
        console.error("Payment error:", error);
        alert("Erreur lors de l'initialisation du paiement.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleManageSubscription = async () => {
    if (!user || !user.workspaceId) return;

    setIsLoading(true);
    try {
        const res = await fetch('/api/stripe/portal', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ workspaceId: user.workspaceId })
        });

        const data = await res.json();
        if (data.url) {
            window.location.href = data.url;
        } else {
            alert(data.error || "Impossible d'accéder au portail.");
        }
    } catch (error) {
        console.error(error);
        alert("Erreur d'accès au portail de facturation.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleContactSales = () => {
    window.location.href = "mailto:sales@citedby.ai?subject=Demande%20Plan%20Agency%20Multi-Clients&body=Bonjour,%20je%20suis%20une%20agence%20et%20je%20souhaite%20gérer%20plusieurs%20projets.";
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-10 relative animate-in fade-in duration-500">
      <button onClick={onBack} className="flex items-center text-gray-400 hover:text-white mb-6 transition-colors">
        <ArrowLeft size={18} className="mr-2" /> Retour au menu
      </button>

      <div className="text-center mb-10">
         <h1 className="text-4xl font-serif font-bold mb-4">Plans & Facturation</h1>
         <p className="text-gray-400 max-w-2xl mx-auto">Gérez votre abonnement AEO ou choisissez la puissance adaptée à votre croissance.</p>
      </div>

      {/* HIGHLIGHTED TABS NAVIGATION */}
      <div className="flex justify-center mb-12">
        <div className="inline-flex bg-white/5 p-1.5 rounded-2xl border border-white/10 relative">
          <button
            onClick={() => setActiveTab('my-plan')}
            className={`px-8 py-3 rounded-xl text-sm font-bold transition-all duration-300 flex items-center gap-2 ${
              activeTab === 'my-plan' 
                ? 'bg-primary text-black shadow-[0_0_20px_rgba(16,185,129,0.3)] scale-[1.02]' 
                : 'text-gray-400 hover:text-white hover:bg-white/5'
            }`}
          >
            <ShieldCheck size={18} className={activeTab === 'my-plan' ? '' : 'opacity-50'} />
            Mon Plan Actuel
          </button>

          <div className="w-px bg-white/10 my-2 mx-1"></div>

          <button
            onClick={() => setActiveTab('pricing')}
            className={`px-8 py-3 rounded-xl text-sm font-bold transition-all duration-300 flex items-center gap-2 ${
              activeTab === 'pricing' 
                ? 'bg-primary text-black shadow-[0_0_20px_rgba(16,185,129,0.3)] scale-[1.02]' 
                : 'text-gray-400 hover:text-white hover:bg-white/5'
            }`}
          >
            <LayoutList size={18} className={activeTab === 'pricing' ? '' : 'opacity-50'} />
            Comparer les offres
          </button>
        </div>
      </div>

      {/* CONTENT: MON PLAN */}
      {activeTab === 'my-plan' && (
        <div className="animate-in fade-in slide-in-from-left-4 duration-300">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-medium text-white">Mon abonnement</h2>
                <span className="text-xs text-gray-500">ID Client: {user?.id || 'GUEST'}</span>
            </div>

            <div className="grid md:grid-cols-2 gap-8">
                {/* Card 1: Plan Status & Usage */}
                <div className="glass-panel p-8 rounded-xl border border-white/10 relative overflow-hidden">
                    {/* Background effects */}
                    <div className="absolute top-0 right-0 w-32 h-32 bg-primary/10 blur-3xl -z-10"></div>

                    {/* Plan Header */}
                    <div className="flex justify-between items-start mb-8">
                        <div className="flex items-center gap-4">
                        <div className="w-14 h-14 rounded-xl bg-gradient-to-br from-primary to-emerald-800 flex items-center justify-center text-white font-bold text-2xl shadow-lg shadow-primary/20">
                            P
                        </div>
                        <div>
                            <h3 className="font-bold text-xl text-white">Plan {user?.plan === 'free' ? 'Starter' : user?.plan === 'enterprise' ? 'Agency' : 'Pro'}</h3>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></span>
                                <span className="text-xs text-emerald-400 font-medium uppercase tracking-wide">Actif</span>
                            </div>
                        </div>
                        </div>
                        <button 
                            onClick={() => setActiveTab('pricing')}
                            className="text-xs bg-white/5 hover:bg-white/10 border border-white/10 px-4 py-2 rounded-lg transition-colors text-gray-300"
                        >
                            Changer d'offre
                        </button>
                    </div>

                    {/* Usage Stats (Projects / Prompts) */}
                    <div className="mb-8 bg-black/20 p-5 rounded-lg border border-white/5 space-y-4">
                        <div>
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-sm text-gray-400">Projets Actifs</span>
                                <span className="text-sm font-bold text-white">
                                    {user?.plan === 'free' ? '1 / 1' : user?.plan === 'enterprise' ? '∞' : '1 / 3'}
                                </span>
                            </div>
                            <div className="h-2 bg-gray-700 rounded-full overflow-hidden">
                                <div className="h-full bg-primary rounded-full" style={{ width: user?.plan === 'free' ? '100%' : '33%' }}></div>
                            </div>
                        </div>

                        <div>
                            <div className="flex justify-between items-end mb-2">
                                <span className="text-sm text-gray-400">Crédits de Génération</span>
                                <span className="text-sm font-bold text-white">{user?.credits} restants</span>
                            </div>
                            <div className="h-2 bg-gray-700 rounded-full overflow-hidden">
                                <div 
                                    className="h-full bg-accent rounded-full transition-all duration-500"
                                    style={{ width: `${Math.min(((user?.credits || 0) / 100) * 100, 100)}%` }}
                                ></div>
                            </div>
                        </div>

                        <p className="text-xs text-gray-500 flex items-center gap-1 pt-2">
                            <Star size={10} className="text-accent" /> Renouvellement des quotas le 01 du mois prochain
                        </p>
                    </div>

                    {/* Features List */}
                    <div className="space-y-4 mb-8">
                        <p className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-2">Fonctionnalités activées</p>
                        {[
                        "1 Projet (Site Web)",
                        "Monitoring Mensuel",
                        "20 Prompts par défaut",
                        "Score de Visibilité IA",
                        "Support Email Standard"
                        ].map((feat, i) => (
                        <div key={i} className="flex items-center gap-3 text-sm text-gray-300">
                            <div className="w-5 h-5 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                                <Check size={12} className="text-primary" />
                            </div>
                            {feat}
                        </div>
                        ))}
                    </div>
                </div>

                {/* Card 2: Billing Info */}
                <div className="space-y-8">
                    <div className="glass-panel p-8 rounded-xl border border-white/10 hover:border-white/20 transition-colors">
                        <h3 className="font-medium text-white mb-6 flex items-center gap-2 text-lg">
                        <CreditCard size={20} className="text-primary" />
                        Facturation & Méthodes de paiement
                        </h3>
                        <div className="space-y-5">
                        <div className="flex justify-between items-center text-sm border-b border-white/5 pb-4">
                            <span className="text-gray-400">Prochaine facture</span>
                            <span className="font-medium text-lg">-</span>
                        </div>
                        <div className="flex justify-between items-center text-sm border-b border-white/5 pb-4">
                            <span className="text-gray-400">Statut Stripe</span>
                            <span className="text-xs text-gray-500 italic">Via Portail</span>
                        </div>
                        </div>
                        <button 
                            onClick={handleManageSubscription}
                            disabled={isLoading}
                            className="w-full mt-6 py-2.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-lg text-sm text-gray-300 hover:text-white flex items-center justify-center gap-2 transition-colors group"
                        >
                            {isLoading ? <Loader2 size={16} className="animate-spin" /> : <CreditCard size={16} className="group-hover:text-primary transition-colors" />}
                            Gérer mon abonnement Stripe
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}

      {/* CONTENT: NOS OFFRES */}
      {activeTab === 'pricing' && (
          <div className="animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="text-center mb-10">
                  <h2 className="text-2xl font-serif font-bold mb-3">Évoluez avec vos besoins</h2>
                  <p className="text-gray-400">Des solutions adaptées de l'indépendant à l'agence marketing.</p>
              </div>

              <div className="grid md:grid-cols-3 gap-6">
                  {/* Plan Starter */}
                  <div className="glass-panel p-6 rounded-xl border border-white/10 flex flex-col hover:border-white/20 transition-all">
                      <div className="mb-4">
                          <h3 className="text-lg font-bold flex items-center gap-2"><Zap size={18} className="text-gray-400" /> Starter</h3>
                          <div className="text-3xl font-bold mt-2 font-serif">Gratuit</div>
                      </div>
                      <p className="text-sm text-gray-400 mb-6 min-h-[40px]">Pour découvrir l'AEO et monitorer un site unique.</p>

                      <div className="border-t border-white/10 pt-4 mb-6 flex-1">
                          <ul className="space-y-3">
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> 1 Projet (Site)</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> Monitoring Mensuel</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> 20 Prompts Standards</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-gray-500" /> Score Visibilité IA</li>
                          </ul>
                      </div>

                      <button 
                        onClick={onNavigateToProjects}
                        className="w-full py-3 border border-white/10 rounded-lg bg-white/5 hover:bg-white/10 text-white transition-colors text-sm font-medium flex items-center justify-center gap-2"
                      >
                         Accéder à mes projets <ArrowRight size={14} />
                      </button>
                  </div>

                  {/* Plan Pro */}
                  <div className="glass-panel p-6 rounded-xl border border-primary/50 bg-primary/5 flex flex-col relative transform hover:-translate-y-1 transition-all duration-300 shadow-[0_0_30px_rgba(16,185,129,0.1)]">
                      <div className="absolute top-0 left-1/2 -translate-x-1/2 bg-primary text-black text-[10px] uppercase font-bold px-3 py-1 rounded-b-lg tracking-wider">Recommandé</div>
                      <div className="mb-4 mt-2">
                          <h3 className="text-lg font-bold text-primary flex items-center gap-2"><Zap size={18} /> Pro</h3>
                          <div className="text-3xl font-bold mt-2 font-serif">89€ <span className="text-sm font-normal text-gray-500 font-sans">/mois</span></div>
                      </div>
                      <p className="text-sm text-gray-300 mb-6 min-h-[40px]">Pour les PME sérieuses qui veulent dominer les réponses IA.</p>

                      <div className="border-t border-white/10 pt-4 mb-6 flex-1">
                          <ul className="space-y-3">
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> <strong>3 Projets</strong></li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Monitoring <strong>Hebdomadaire</strong></li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Exports PDF & CSV</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Moteur de Recommandations</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-primary" /> Générateur Packs Contenu</li>
                          </ul>
                      </div>

                      <button 
                        onClick={handleSubscribePro}
                        disabled={isLoading}
                        className="w-full py-3 bg-primary text-black font-bold rounded-lg hover:bg-primaryDark transition-colors text-sm flex items-center justify-center gap-2 shadow-lg shadow-primary/20"
                      >
                        {isLoading ? <Loader2 className="animate-spin" size={16} /> : <CreditCard size={16} />} 
                        S'abonner maintenant
                      </button>
                  </div>

                  {/* Plan Agency */}
                  <div className="glass-panel p-6 rounded-xl border border-white/10 flex flex-col hover:border-white/20 transition-all">
                      <div className="mb-4">
                          <h3 className="text-lg font-bold flex items-center gap-2"><Briefcase size={18} className="text-white" /> Agency</h3>
                          <div className="text-3xl font-bold mt-2 font-serif">Sur devis</div>
                      </div>
                      <p className="text-sm text-gray-400 mb-6 min-h-[40px]">Gestion multi-clients et rapports en marque blanche.</p>

                      <div className="border-t border-white/10 pt-4 mb-6 flex-1">
                          <ul className="space-y-3">
                              <li className="text-sm flex gap-2"><Check size={16} className="text-white" /> Tout du plan Pro</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-white" /> Espaces de travail illimités</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-white" /> <strong>Rapports Marque Blanche</strong></li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-white" /> Accès API Full</li>
                              <li className="text-sm flex gap-2"><Check size={16} className="text-white" /> Opérations Bulk (Prompts)</li>
                          </ul>
                      </div>

                      <button 
                        onClick={handleContactSales}
                        className="w-full py-3 bg-white text-black font-bold rounded-lg hover:bg-gray-200 transition-colors text-sm flex items-center justify-center gap-2"
                      >
                        Contacter l'équipe <Briefcase size={14} />
                      </button>
                  </div>
              </div>
          </div>
      )}

    </div>
  );
};

export default Plan;"}

{"content":"@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  :root {
    --background: 0 0% 100%;
    --foreground: 222.2 84% 4.9%;
    --card: 0 0% 100%;
    --card-foreground: 222.2 84% 4.9%;
    --popover: 0 0% 100%;
    --popover-foreground: 222.2 84% 4.9%;
    --primary: 222.2 47.4% 11.2%;
    --primary-foreground: 210 40% 98%;
    --secondary: 210 40% 96.1%;
    --secondary-foreground: 222.2 47.4% 11.2%;
    --muted: 210 40% 96.1%;
    --muted-foreground: 215.4 16.3% 46.9%;
    --accent: 210 40% 96.1%;
    --accent-foreground: 222.2 47.4% 11.2%;
    --destructive: 0 84.2% 60.2%;
    --destructive-foreground: 210 40% 98%;
    --border: 214.3 31.8% 91.4%;
    --input: 214.3 31.8% 91.4%;
    --ring: 222.2 84% 4.9%;
    --radius: 0.5rem;
  }

  .dark {
    --background: 222.2 84% 4.9%;
    --foreground: 210 40% 98%;
    --card: 222.2 84% 4.9%;
    --card-foreground: 210 40% 98%;
    --popover: 222.2 84% 4.9%;
    --popover-foreground: 210 40% 98%;
    --primary: 210 40% 98%;
    --primary-foreground: 222.2 47.4% 11.2%;
    --secondary: 217.2 32.6% 17.5%;
    --secondary-foreground: 210 40% 98%;
    --muted: 217.2 32.6% 17.5%;
    --muted-foreground: 215 20.2% 65.1%;
    --accent: 217.2 32.6% 17.5%;
    --accent-foreground: 210 40% 98%;
    --destructive: 0 62.8% 30.6%;
    --destructive-foreground: 210 40% 98%;
    --border: 217.2 32.6% 17.5%;
    --input: 217.2 32.6% 17.5%;
    --ring: 212.7 26.8% 83.9%;
  }
}

body {
  @apply bg-background text-foreground;
}

.glass-panel {
  @apply bg-white/5 backdrop-blur-md border border-white/5;
}"}

{"content":"import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);"}
